    48→/**
    49→ * Generate deposit parameters for a quest (frontend constructs tx from these).
    50→ * @param depositorUserId - The user making the deposit. Owner gets original questId; sponsors get sub-questId.
    51→ */
    52→export async function getDepositParams(
    53→    prisma: PrismaClient,
    54→    questId: string,
    55→    depositorUserId?: string,
    56→    chainId?: number,
    57→): Promise<DepositParams & { escrowQuestId: string }> {
    58→    const quest = await prisma.quest.findUnique({ where: { id: questId } });
    59→    if (!quest) throw new Error('Quest not found');
    60→
    61→    const isOwner = !depositorUserId || quest.creatorUserId === depositorUserId;
    62→    const escrowQuestId = isOwner
    63→        ? uuidToBytes32(questId)
    64→        : generateSubQuestId(questId, depositorUserId);
    65→
    66→    let targetChainId = chainId ?? quest.cryptoChainId ?? resolveChainIdFromNetwork(quest.network) ?? escrowConfig.defaultChainId;
    67→    if (!isChainAllowed(targetChainId)) {
    68→        targetChainId = escrowConfig.defaultChainId;
    69→    }
    70→    const chain = getChainById(targetChainId);
    71→    if (!chain) throw new Error(`Unsupported chain: ${targetChainId}`);
    72→
    73→    const rewardType = quest.rewardType.toUpperCase();
    74→    const tokenInfo = getTokenInfo(targetChainId, rewardType);
    75→    if (!tokenInfo) {
    76→        throw new Error(`Token ${rewardType} not available on chain ${targetChainId}`);
    77→    }
    78→
    79→    const rewardAmountNum = Number(quest.rewardAmount);
    80→    const totalFunded = Number(quest.totalFunded ?? 0);
    81→
    82→    // Suggest the remaining needed amount (or full reward if nothing funded yet)
    83→    let depositAmount = rewardAmountNum - totalFunded;
    84→    if (depositAmount <= 0) depositAmount = rewardAmountNum; // already fully funded — show full amount as reference
    85→
    86→    const amountSmallestUnit = toSmallestUnit(depositAmount, tokenInfo.decimals);
    87→    const expiresAt = quest.expiresAt ? Math.floor(quest.expiresAt.getTime() / 1000) : 0;
    88→
    89→    // Create pending QuestDeposit record if depositor is known
    90→    if (depositorUserId) {
    91→        const existingDeposit = await prisma.questDeposit.findFirst({
    92→            where: { questId, userId: depositorUserId, status: 'pending' },
    93→        });
    94→        if (!existingDeposit) {
    95→            await prisma.questDeposit.create({
    96→                data: {
    97→                    questId,
    98→                    escrowQuestId,
    99→                    userId: depositorUserId,
   100→                    amount: depositAmount,
   101→                    tokenAddress: tokenInfo.address,
   102→                    chainId: targetChainId,
   103→                    walletAddress: '',
   104→                    status: 'pending',
   105→                },
   106→            });
   107→        }
   108→    }
   109→
   110→    return {
   111→        contractAddress: getContractAddress(targetChainId),
   112→        questIdBytes32: escrowQuestId,
   113→        escrowQuestId,
   114→        tokenAddress: tokenInfo.address,
   115→        tokenSymbol: tokenInfo.symbol,
   116→        tokenDecimals: tokenInfo.decimals,
   117→        amount: depositAmount,
   118→        amountSmallestUnit: amountSmallestUnit.toString(),
   119→        chainId: targetChainId,
   120→        chainName: chain.name,
   121→        expiresAt,
   122→        isNative: isNativeToken(tokenInfo.address),
   123→    };
   124→}
