   128→export interface EscrowStatus {
   129→    sponsor: string;
   130→    token: string;
   131→    deposited: string;
   132→    distributed: string;
   133→    refunded: string;
   134→    remaining: string;
   135→    createdAt: number;
   136→    expiresAt: number;
   137→    cancelled: boolean;
   138→    depositedHuman: number;
   139→    distributedHuman: number;
   140→    refundedHuman: number;
   141→    remainingHuman: number;
   142→}
