   144→/**
   145→ * Read on-chain escrow status for a quest.
   146→ */
   147→export async function getEscrowStatus(
   148→    questId: string,
   149→    chainId: number,
   150→): Promise<EscrowStatus | null> {
   151→    const client = getPublicClient(chainId);
   152→    const questIdBytes32 = uuidToBytes32(questId);
   153→
   154→    try {
   155→        const result = await client.readContract({
   156→            address: getContractAddress(chainId),
   157→            abi: ESCROW_ABI,
   158→            functionName: 'getQuest',
   159→            args: [questIdBytes32],
   160→        }) as any;
   161→
   162→        if (result.sponsor === '0x0000000000000000000000000000000000000000') return null;
   163→
   164→        const tokenInfo = Object.values(TOKEN_REGISTRY[chainId] || {}).find(
   165→            t => t.address.toLowerCase() === result.token.toLowerCase()
   166→        );
   167→        const decimals = tokenInfo?.decimals || 18;
   168→
   169→        const deposited = BigInt(result.deposited);
   170→        const distributed = BigInt(result.distributed);
   171→        const refunded = BigInt(result.refunded);
   172→        const remaining = deposited - distributed - refunded;
   173→
   174→        return {
   175→            sponsor: result.sponsor,
   176→            token: result.token,
   177→            deposited: deposited.toString(),
   178→            distributed: distributed.toString(),
   179→            refunded: refunded.toString(),
   180→            remaining: remaining.toString(),
   181→            createdAt: Number(result.createdAt),
   182→            expiresAt: Number(result.expiresAt),
   183→            cancelled: result.cancelled,
   184→            depositedHuman: fromSmallestUnit(deposited, decimals),
   185→            distributedHuman: fromSmallestUnit(distributed, decimals),
   186→            refundedHuman: fromSmallestUnit(refunded, decimals),
   187→            remainingHuman: fromSmallestUnit(remaining, decimals),
   188→        };
   189→    } catch (err: any) {
   190→        if (err.message?.includes('QuestNotFound')) return null;
   191→        throw err;
   192→    }
   193→}
