   197→import {
   198→    computeFcfs,
   199→    computeLeaderboard,
   200→    computeLuckyDraw,
   201→    type PayoutResult,
   202→    type Participant,
   203→} from './distribution-calculator';
   204→
   205→export interface PayoutEntry {
   206→    participationId: string;
   207→    agentId: string;
   208→    wallet: string;
   209→    amount: bigint;
   210→}
   211→
   212→/**
   213→ * Calculate payout distribution for a quest based on its type.
   214→ * Uses extracted calculator module for pure computation.
   215→ */
   216→export async function calculateDistribution(
   217→    prisma: PrismaClient,
   218→    questId: string,
   219→    overrideTotalFunded?: number,
   220→): Promise<PayoutEntry[]> {
   221→    const quest = await prisma.quest.findUnique({ where: { id: questId } });
   222→    if (!quest) throw new Error('Quest not found');
   223→
   224→    if (quest.status !== 'live' && quest.status !== 'completed') {
   225→        throw new Error(`Cannot distribute: quest status is "${quest.status}"`);
   226→    }
   227→
   228→    const chainId = quest.cryptoChainId || resolveChainIdFromNetwork(quest.network) || escrowConfig.defaultChainId;
   229→    const tokenInfo = getTokenInfo(chainId, quest.rewardType.toUpperCase());
   230→    if (!tokenInfo) throw new Error(`Token ${quest.rewardType} not found for chain ${chainId}`);
   231→
   232→    const totalAmountHuman = overrideTotalFunded ?? Number(quest.rewardAmount);
   233→    const totalAmount = toSmallestUnit(totalAmountHuman, tokenInfo.decimals);
   234→
   235→    const participations = await prisma.questParticipation.findMany({
   236→        where: {
   237→            questId,
   238→            status: { in: ['completed', 'submitted', 'verified'] },
   239→            payoutWallet: { not: null },
   240→        },
   241→        orderBy: [{ completedAt: 'asc' }, { joinedAt: 'asc' }],
   242→    });
   243→
   244→    if (participations.length === 0) return [];
   245→
   246→    // Check for already-distributed payouts
   247→    const alreadyPaid = participations.some(p => p.payoutStatus === 'paid');
   248→    if (alreadyPaid) throw new Error('Quest already has paid distributions');
   249→
   250→    const participants: Participant[] = participations.map(p => ({
   251→        id: p.id,
   252→        agentId: p.agentId,
   253→        wallet: p.payoutWallet!,
   254→    }));
   255→
   256→    let results: PayoutResult[];
   257→
   258→    switch (quest.type) {
   259→        case 'FCFS':
   260→            results = computeFcfs(totalAmount, quest.totalSlots, participants);
   261→            break;
   262→        case 'LEADERBOARD':
   263→            results = computeLeaderboard(totalAmount, participants, quest.rewardTiers as number[] | null);
   264→            break;
   265→        case 'LUCKY_DRAW':
   266→            results = computeLuckyDraw(totalAmount, quest.totalSlots, participants);
   267→            break;
   268→        default:
   269→            throw new Error(`Unknown quest type: ${quest.type}`);
   270→    }
   271→
   272→    return results.map(r => ({
   273→        participationId: r.participantId,
   274→        agentId: r.agentId,
   275→        wallet: r.wallet,
   276→        amount: r.amount,
   277→    }));
   278→}
