   280→// ─── Write Contract With Retry ────────────────────────────────────────────────
   281→
   282→/**
   283→ * Write a contract call with one automatic retry on nonce/replacement errors.
   284→ */
   285→async function writeContractWithRetry(
   286→    walletClient: ReturnType<typeof getOperatorWalletClient>,
   287→    params: Parameters<ReturnType<typeof getOperatorWalletClient>['writeContract']>[0],
   288→    maxRetries = 1,
   289→): Promise<`0x${string}`> {
   290→    for (let attempt = 0; attempt <= maxRetries; attempt++) {
   291→        try {
   292→            return await walletClient.writeContract(params as any);
   293→        } catch (err: any) {
   294→            const isNonceError = err.message?.includes('nonce') || err.message?.includes('replacement');
   295→            if (isNonceError && attempt < maxRetries) {
   296→                await new Promise(r => setTimeout(r, 2000));
   297→                continue;
   298→            }
   299→            throw err;
   300→        }
   301→    }
   302→    throw new Error('Unreachable');
   303→}
