   305→// ─── Execute On-chain Distribute ─────────────────────────────────────────────
   306→
   307→/**
   308→ * Submit on-chain distribute txs. Returns array of tx hashes (one per sub-escrow).
   309→ * For single-deposit quests, this is backward-compatible (returns 1 hash).
   310→ */
   311→export async function executeDistribute(
   312→    prisma: PrismaClient,
   313→    questId: string,
   314→    chainId: number,
   315→): Promise<string | string[]> {
   316→    const quest = await prisma.quest.findUnique({ where: { id: questId } });
   317→    if (!quest) throw new Error('Quest not found');
   318→
   319→    const totalFunded = Number(quest.totalFunded ?? quest.rewardAmount);
   320→    const payouts = await calculateDistribution(prisma, questId, totalFunded);
   321→    if (payouts.length === 0) throw new Error('No eligible participants for distribution');
   322→
   323→    // Get all confirmed deposits
   324→    const deposits = await prisma.questDeposit.findMany({
   325→        where: { questId, status: 'confirmed' },
   326→    });
   327→
   328→    const walletClient = getOperatorWalletClient(chainId);
   329→    const publicClient = getPublicClient(chainId);
   330→    const contractAddr = getContractAddress(chainId);
   331→    const txHashes: string[] = [];
   332→
   333→    if (deposits.length === 0) {
   334→        // Legacy path: no QuestDeposit records, use original questIdBytes32
   335→        const questIdBytes32 = uuidToBytes32(questId);
   336→        const recipients = payouts.map(p => p.wallet as `0x${string}`);
   337→        const amounts = payouts.map(p => p.amount);
   338→
   339→        await publicClient.simulateContract({
   340→            address: contractAddr, abi: ESCROW_ABI,
   341→            functionName: 'distribute',
   342→            args: [questIdBytes32, recipients, amounts],
   343→            account: walletClient.account!,
   344→        });
   345→        const txHash = await writeContractWithRetry(walletClient, {
   346→            address: contractAddr, abi: ESCROW_ABI,
   347→            functionName: 'distribute',
   348→            args: [questIdBytes32, recipients, amounts],
   349→        });
   350→        txHashes.push(txHash);
   351→    } else {
   352→        // Multi-deposit: proportional distribution per sub-escrow
   353→        // Use BigInt arithmetic to avoid precision loss with 18-decimal tokens
   354→        const totalPayoutAmount = payouts.reduce((sum, p) => sum + p.amount, 0n);
   355→
   356→        for (const deposit of deposits) {
   357→            const depositAmountBig = toSmallestUnit(Number(deposit.amount), quest.tokenDecimals || 6);
   358→            const recipients = payouts.map(p => p.wallet as `0x${string}`);
   359→            // Proportional: (payout.amount * depositAmount) / totalPayoutAmount
   360→            const amounts = payouts.map(p => (p.amount * depositAmountBig) / totalPayoutAmount);
   361→
   362→            await publicClient.simulateContract({
   363→                address: contractAddr, abi: ESCROW_ABI,
   364→                functionName: 'distribute',
   365→                args: [deposit.escrowQuestId as `0x${string}`, recipients, amounts],
   366→                account: walletClient.account!,
   367→            });
   368→            const txHash = await writeContractWithRetry(walletClient, {
   369→                address: contractAddr, abi: ESCROW_ABI,
   370→                functionName: 'distribute',
   371→                args: [deposit.escrowQuestId as `0x${string}`, recipients, amounts],
   372→            });
   373→            txHashes.push(txHash);
   374→            console.log(`[escrow:distribute] deposit ${deposit.id} tx: ${txHash}`);
   375→        }
   376→    }
   377→
   378→    // Mark pending — poller upgrades to 'paid' when QuestDistributed event arrives
   379→    const decimals = quest.tokenDecimals || 6;
   380→    for (const payout of payouts) {
   381→        await prisma.questParticipation.update({
   382→            where: { id: payout.participationId },
   383→            data: { payoutAmount: fromSmallestUnit(payout.amount, decimals), payoutStatus: 'pending', payoutTxHash: txHashes[0] },
   384→        });
   385→    }
   386→
   387→    console.log(`[escrow:distribute] Quest ${questId}: ${txHashes.length} tx(s) submitted`);
   388→    return txHashes.length === 1 ? txHashes[0] : txHashes;
   389→}
