    18→// ─── FCFS ───────────────────────────────────────────────────────────────────
    19→
    20→/** First N completed agents split reward equally. */
    21→export function computeFcfs(
    22→    totalAmount: bigint,
    23→    totalSlots: number,
    24→    participants: Participant[],
    25→): PayoutResult[] {
    26→    const winners = participants.slice(0, totalSlots);
    27→    if (winners.length === 0) return [];
    28→    return splitEqual(totalAmount, winners);
    29→}
    30→
    31→// ─── LEADERBOARD ────────────────────────────────────────────────────────────
    32→
    33→/**
    34→ * Distribute by custom tier percentages.
    35→ * tiers = [40, 25, 15, 20] means rank1=40%, rank2=25%, rank3=15%, rest split 20%.
    36→ * If tiers is null/empty, falls back to inverse-rank proportional.
    37→ */
    38→export function computeLeaderboard(
    39→    totalAmount: bigint,
    40→    participants: Participant[],
    41→    tiers?: number[] | null,
    42→): PayoutResult[] {
    43→    if (participants.length === 0) return [];
    44→    if (tiers && tiers.length > 0) {
    45→        return computeLeaderboardTiers(totalAmount, participants, tiers);
    46→    }
    47→    return computeLeaderboardProportional(totalAmount, participants);
    48→}
    49→
    50→function computeLeaderboardTiers(
    51→    totalAmount: bigint,
    52→    participants: Participant[],
    53→    tiers: number[],
    54→): PayoutResult[] {
    55→    const results: PayoutResult[] = [];
    56→    let distributed = 0n;
    57→
    58→    for (let i = 0; i < participants.length; i++) {
    59→        let amount: bigint;
    60→
    61→        if (i < tiers.length - 1) {
    62→            // Named tier: exact percentage
    63→            amount = (totalAmount * BigInt(tiers[i])) / 100n;
    64→        } else if (tiers.length > 0 && participants.length > tiers.length - 1) {
    65→            // "Rest" bucket: last tier % split among remaining participants
    66→            const restPercent = tiers[tiers.length - 1];
    67→            const restPool = (totalAmount * BigInt(restPercent)) / 100n;
    68→            const restCount = participants.length - (tiers.length - 1);
    69→            amount = restPool / BigInt(restCount);
    70→        } else {
    71→            amount = 0n;
    72→        }
    73→
    74→        distributed += amount;
    75→        results.push({
    76→            participantId: participants[i].id,
    77→            agentId: participants[i].agentId,
    78→            wallet: participants[i].wallet,
    79→            amount,
    80→        });
    81→    }
    82→
    83→    // Dust to first winner
    84→    const dust = totalAmount - distributed;
    85→    if (dust > 0n && results.length > 0) {
    86→        results[0].amount += dust;
    87→    }
    88→
    89→    return results;
    90→}
    91→
    92→function computeLeaderboardProportional(
    93→    totalAmount: bigint,
    94→    participants: Participant[],
    95→): PayoutResult[] {
    96→    const n = participants.length;
    97→    // rank 1 gets n shares, rank 2 gets n-1, ... rank n gets 1
    98→    const totalShares = BigInt((n * (n + 1)) / 2);
    99→    const results: PayoutResult[] = [];
   100→    let distributed = 0n;
   101→
   102→    for (let i = 0; i < n; i++) {
   103→        const shares = BigInt(n - i);
   104→        const amount = (totalAmount * shares) / totalShares;
   105→        distributed += amount;
   106→        results.push({
   107→            participantId: participants[i].id,
   108→            agentId: participants[i].agentId,
   109→            wallet: participants[i].wallet,
   110→            amount,
   111→        });
   112→    }
   113→
   114→    // Dust to first winner
   115→    const dust = totalAmount - distributed;
   116→    if (dust > 0n && results.length > 0) {
   117→        results[0].amount += dust;
   118→    }
   119→
   120→    return results;
   121→}
   122→
   123→// ─── LUCKY DRAW ─────────────────────────────────────────────────────────────
   124→
   125→/** Crypto-safe random selection of N winners, equal split. */
   126→export function computeLuckyDraw(
   127→    totalAmount: bigint,
   128→    totalSlots: number,
   129→    participants: Participant[],
   130→): PayoutResult[] {
   131→    if (participants.length === 0) return [];
   132→    const maxWinners = Math.min(totalSlots, participants.length);
   133→    const winners = cryptoShuffle([...participants]).slice(0, maxWinners);
   134→    return splitEqual(totalAmount, winners);
   135→}
   136→
   137→// ─── Helpers ────────────────────────────────────────────────────────────────
   138→
   139→/** Equal split with dust to first recipient. */
   140→function splitEqual(totalAmount: bigint, participants: Participant[]): PayoutResult[] {
   141→    const perPerson = totalAmount / BigInt(participants.length);
   142→    const results: PayoutResult[] = participants.map(p => ({
   143→        participantId: p.id,
   144→        agentId: p.agentId,
   145→        wallet: p.wallet,
   146→        amount: perPerson,
   147→    }));
   148→
   149→    // Dust to first winner
   150→    const dust = totalAmount - perPerson * BigInt(participants.length);
   151→    if (dust > 0n && results.length > 0) {
   152→        results[0].amount += dust;
   153→    }
   154→
   155→    return results;
   156→}
   157→
   158→/** Fisher-Yates shuffle using crypto.randomBytes for unbiased randomness. */
   159→function cryptoShuffle<T>(arr: T[]): T[] {
   160→    for (let i = arr.length - 1; i > 0; i--) {
   161→        const j = cryptoRandomInt(i + 1);
   162→        [arr[i], arr[j]] = [arr[j], arr[i]];
   163→    }
   164→    return arr;
   165→}
   166→
   167→/** Generate a crypto-safe random integer in [0, max). */
   168→function cryptoRandomInt(max: number): number {
   169→    const bytes = randomBytes(4);
   170→    const val = bytes.readUInt32BE(0);
   171→    return val % max;
   172→}
