   129→export async function handleQuestDistributed(
   130→    prisma: PrismaClient,
   131→    questIdBytes32: string,
   132→    recipients: string[],
   133→    amounts: bigint[],
   134→    totalPayout: bigint,
   135→    txHash: string,
   136→    chainId: number,
   137→): Promise<void> {
   138→    const resolved = await resolveLogicalQuestId(prisma, questIdBytes32);
   139→    if (!resolved) {
   140→        console.warn(`[escrow:distributed] Unknown escrowQuestId: ${questIdBytes32}`);
   141→        return;
   142→    }
   143→    const { questId } = resolved;
   144→    const quest = await prisma.quest.findUnique({ where: { id: questId } });
   145→    if (!quest) {
   146→        console.warn(`[escrow:distributed] Quest ${questId} not found`);
   147→        return;
   148→    }
   149→
   150→    const decimals = resolveDecimals(chainId, quest.tokenAddress, quest.tokenDecimals);
   151→
   152→    for (let i = 0; i < recipients.length; i++) {
   153→        const wallet = recipients[i].toLowerCase();
   154→        const participation = await prisma.questParticipation.findFirst({
   155→            where: { questId, payoutWallet: { equals: wallet, mode: 'insensitive' } },
   156→        });
   157→        if (!participation) {
   158→            console.warn(`[escrow:distributed] No participation for wallet ${wallet} on quest ${questId}`);
   159→            continue;
   160→        }
   161→        if (participation.payoutStatus === 'paid') continue; // idempotent
   162→
   163→        await prisma.questParticipation.update({
   164→            where: { id: participation.id },
   165→            data: {
   166→                payoutAmount: fromSmallestUnit(amounts[i], decimals),
   167→                payoutStatus: 'paid',
   168→                payoutTxHash: txHash,
   169→            },
   170→        });
   171→    }
   172→
   173→    if (quest.status !== 'completed') {
   174→        await prisma.quest.update({ where: { id: questId }, data: { status: 'completed' } });
   175→    }
   176→
   177→    // Issue LLM bonus keys asynchronously — failure must not affect distribution outcome
   178→    if (quest.llmKeyRewardEnabled) {
   179→        issueLlmKeysForQuest(prisma, questId).catch((err) =>
   180→            console.error('[llm-reward] Failed during auto-issue after distribution:', err),
   181→        );
   182→    }
   183→
   184→    console.log(`[escrow:distributed] Quest ${questId}: ${fromSmallestUnit(totalPayout, decimals)} to ${recipients.length} recipients (tx: ${txHash})`);
   185→}
